int bsearch_custom(int *arr, int n, int x) {
    int *low = arr, *high = arr + n - 1;
    while (low <= high) {
        int *mid = low + (high - low) / 2;
        if (*mid == x) return mid - arr;
        if (*mid < x) low = mid + 1;
        else high = mid - 1;
    }
    return -1;
}
