void *bsearch_ptr(void *key, void *base, size_t n, size_t size,
                   int (*cmp)(const void*, const void*)) {
    char *p = (char*)base;
    while (n > 0) {
        size_t h = n / 2;
        char *mid = p + h * size;
        int c = cmp(key, mid);
        if (c == 0) return mid;
        if (c > 0) { p = mid + size; n -= h + 1; }
        else n = h;
    }
    return NULL;
}
