int *partition(int *low, int *high) {
    int pivot = *high;
    int *i = low - 1;
    for (int *j = low; j < high; j++) {
        if (*j < pivot) {
            i++;
            int t = *i; *i = *j; *j = t;
        }
    }
    int t = *(i+1); *(i+1) = *high; *high = t;
    return i + 1;
}
