int **createPascal(int n) {
    int **t = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        t[i] = (int*)malloc((i+1) * sizeof(int));
        t[i][0] = t[i][i] = 1;
        for (int j = 1; j < i; j++)
            t[i][j] = t[i-1][j-1] + t[i-1][j];
    }
    return t;
}
